```rust
use actix_web::{dev::ServiceRequest, web, HttpMessage};
use crate::db::DbPool;
use crate::models::user::User;
use uuid::Uuid;

// AuthenticatedUser is stored in request extensions after token validation
#[derive(Debug, Clone)]
pub struct AuthenticatedUser {
    pub user_id: Uuid,
    pub username: String,
    pub roles: Vec<String>,
    pub account_state: String,
}

// Extract Bearer token from Authorization header
pub fn extract_bearer_token(req: &ServiceRequest) -> Option<String> {
    req.headers()
        .get("Authorization")
        .and_then(|v| v.to_str().ok())
        .and_then(|v| v.strip_prefix("Bearer "))
        .map(|s| s.to_string())
}
```

Also implement:
```rust
pub async fn resolve_authenticated_user(
    pool: &DbPool,
    token: &str,
) -> Result<AuthenticatedUser, crate::errors::AppError>
```
This should:
1. Query sessions table: `SELECT * FROM sessions WHERE token = $1 AND expires_at > NOW()`
2. If not found, return `AppError::Unauthorized("Invalid or expired session".into())`
3. Query user by session.user_id
4. Check account_state is "active", else return Forbidden
5. Query roles via `SELECT r.name FROM roles r JOIN user_roles ur ON r.id = ur.role_id WHERE ur.user_id = $1`
6. Return AuthenticatedUser

