use yew::prelude::*;
use yew_router::prelude::*;
use crate::router::Route;
use crate::state::{AppState, AppStateContext};
use crate::api::auth;

#[function_component(LoginPage)]
pub fn login_page() -> Html {
    let state = use_context::<AppStateContext>().expect("AppState context not found");
    let navigator = use_navigator().unwrap();

    let username = use_state(String::new);
    let password = use_state(String::new);
    let error = use_state(|| Option::<String>::None);
    let loading = use_state(|| false);

    // Redirect if already authenticated
    {
        let state = state.clone();
        let navigator = navigator.clone();
        use_effect_with(state.clone(), move |state| {
            if state.is_authenticated() {
                navigator.push(&Route::Home);
            }
        });
    }

    let on_username_input = {
        let username = username.clone();
        Callback::from(move |e: InputEvent| {
            let input: web_sys::HtmlInputElement = e.target_unchecked_into();
            username.set(input.value());
        })
    };

    let on_password_input = {
        let password = password.clone();
        Callback::from(move |e: InputEvent| {
            let input: web_sys::HtmlInputElement = e.target_unchecked_into();
            password.set(input.value());
        })
    };

    let on_submit = {
        let username = username.clone();
        let password = password.clone();
        let error = error.clone();
        let loading = loading.clone();
        let state = state.clone();
        let navigator = navigator.clone();

        Callback::from(move |e: SubmitEvent| {
            e.prevent_default();

            let u = (*username).clone();
            let p = (*password).clone();

            if u.is_empty() || p.is_empty() {
                error.set(Some("Username and password are required.".into()));
                return;
            }

            let error = error.clone();
            let loading = loading.clone();
            let state = state.clone();
            let navigator = navigator.clone();

            loading.set(true);
            error.set(None);

            wasm_bindgen_futures::spawn_local(async move {
                match auth::login(u, p).await {
                    Ok(resp) => {
                        let mut new_state = (*state).clone();
                        new_state.login(resp.token, resp.user);
                        state.set(new_state);
                        navigator.push(&Route::Home);
                    }
                    Err(e) => {
                        error.set(Some(format!("Login failed: {}", e)));
                        loading.set(false);
                    }
                }
            });
        })
    };

    let error_html = if let Some(msg) = &*error {
        html! { <p class="error-msg">{ msg }</p> }
    } else {
        html! {}
    };

    html! {
        <div class="login-container">
            <div class="login-box">
                <h1>{ "Meridian" }</h1>
                <p class="subtitle">{ "Check-In & Commerce Operations Suite" }</p>
                <form onsubmit={on_submit}>
                    <div class="form-group">
                        <label for="username">{ "Username" }</label>
                        <input
                            id="username"
                            type="text"
                            placeholder="Enter your username"
                            value={(*username).clone()}
                            oninput={on_username_input}
                            autocomplete="username"
                            disabled={*loading}
                        />
                    </div>
                    <div class="form-group">
                        <label for="password">{ "Password" }</label>
                        <input
                            id="password"
                            type="password"
                            placeholder="Enter your password"
                            value={(*password).clone()}
                            oninput={on_password_input}
                            autocomplete="current-password"
                            disabled={*loading}
                        />
                    </div>
                    <button class="btn-primary" type="submit" disabled={*loading}>
                        if *loading { "Signing in…" } else { "Sign In" }
                    </button>
                    { error_html }
                </form>
            </div>
        </div>
    }
}
