1	use yew::prelude::*;
2	use yew_router::prelude::*;
3	use crate::router::Route;
4	use crate::state::{AppState, AppStateContext};
5	use crate::components::layout::Layout;
6	use crate::pages::login::LoginPage;
7	use crate::pages::unauthorized::UnauthorizedPage;
8	use crate::pages::home::HomePage;
9	use crate::api::auth;
10	
11	fn switch(route: Route) -> Html {
12	    match route {
13	        Route::Login => html! { <LoginPage /> },
14	        Route::Unauthorized => html! { <UnauthorizedPage /> },
15	        Route::Home | Route::NotFound => html! { <AuthGuard /> },
16	    }
17	}
18	
19	#[function_component(AuthGuard)]
20	fn auth_guard() -> Html {
21	    let state = use_context::<AppStateContext>().expect("AppState context not found");
22	    let navigator = use_navigator().unwrap();
23	
24	    if !state.is_authenticated() {
25	        let nav = navigator.clone();
26	        use_effect_with((), move |_| {
27	            nav.push(&Route::Login);
28	        });
29	        html! { <div class="loading">{ "Redirecting\u{2026}" }</div> }
30	    } else {
31	        html! { <HomePage /> }
32	    }
33	}
34	
35	#[function_component(App)]
36	pub fn app() -> Html {
37	    let app_state = use_state(AppState::default);
38	
39	    // On mount, if we have a stored token, validate it by fetching the current user.
40	    {
41	        let app_state = app_state.clone();
42	        use_effect_with((), move |_| {
43	            let app_state = app_state.clone();
44	            if let Some(token) = (*app_state).token.clone() {
45	                wasm_bindgen_futures::spawn_local(async move {
46	                    match auth::me(&token).await {
47	                        Ok(user) => {
48	                            let mut new_state = (*app_state).clone();
49	                            new_state.user = Some(user);
50	                            app_state.set(new_state);
51	                        }
52	                        Err(_) => {
53	                            // Token is invalid or expired — clear it.
54	                            let mut new_state = (*app_state).clone();
55	                            new_state.logout();
56	                            app_state.set(new_state);
57	                        }
58	                    }
59	                });
60	            }
61	        });
62	    }
63	
64	    let on_logout = {
65	        let app_state = app_state.clone();
66	        Callback::from(move |_: ()| {
67	            let token = (*app_state).token.clone();
68	            let app_state = app_state.clone();
69	            wasm_bindgen_futures::spawn_local(async move {
70	                if let Some(t) = token {
71	                    let _ = auth::logout(&t).await;
72	                }
73	                let mut new_state = (*app_state).clone();
74	                new_state.logout();
75	                app_state.set(new_state);
76	            });
77	        })
78	    };
79	
80	    html! {
81	        <ContextProvider<AppStateContext> context={app_state.clone()}>
82	            <BrowserRouter>
83	                <div id="app">
84	                    <Layout on_logout={on_logout}>
85	                        <Switch<Route> render={switch} />
86	                    </Layout>
87	                </div>
88	            </BrowserRouter>
89	        </ContextProvider<AppStateContext>>
90	    }
91	}
