use actix_web::{HttpResponse, ResponseError};
use serde_json::json;
use thiserror::Error;

#[derive(Debug, Error)]
pub enum AppError {
    #[error("Database error: {0}")]
    DatabaseError(#[from] sqlx::Error),

    #[error("Not found: {0}")]
    NotFound(String),

    #[error("Unauthorized: {0}")]
    Unauthorized(String),

    #[error("Forbidden: {0}")]
    Forbidden(String),

    #[error("Validation error: {0}")]
    ValidationError(String),

    #[error("Internal error: {0}")]
    InternalError(String),

    #[error("Conflict: {0}")]
    ConflictError(String),
}

impl ResponseError for AppError {
    fn error_response(&self) -> HttpResponse {
        let message = self.to_string();
        let body = json!({ "error": message });

        match self {
            AppError::DatabaseError(_) => {
                HttpResponse::InternalServerError().json(body)
            }
            AppError::NotFound(_) => HttpResponse::NotFound().json(body),
            AppError::Unauthorized(_) => HttpResponse::Unauthorized().json(body),
            AppError::Forbidden(_) => HttpResponse::Forbidden().json(body),
            AppError::ValidationError(_) => {
                HttpResponse::UnprocessableEntity().json(body)
            }
            AppError::InternalError(_) => {
                HttpResponse::InternalServerError().json(body)
            }
            AppError::ConflictError(_) => HttpResponse::Conflict().json(body),
        }
    }
}

impl From<argon2::password_hash::Error> for AppError {
    fn from(e: argon2::password_hash::Error) -> Self {
        match e {
            argon2::password_hash::Error::Password => {
                AppError::Unauthorized("Invalid credentials".into())
            }
            other => AppError::InternalError(other.to_string()),
        }
    }
}

use actix_web::{web, HttpRequest, HttpResponse};
use chrono::{Duration, Utc};
use rand::Rng;
use serde::{Deserialize, Serialize};
use uuid::Uuid;

use crate::db::DbPool;
use crate::errors::AppError;
use crate::middleware::auth::resolve_authenticated_user;
use crate::models::user::{User, UserPublic};

// ---------------------------------------------------------------------------
// Request / response types
// ---------------------------------------------------------------------------

#[derive(Debug, Deserialize)]
pub struct LoginRequest {
    pub username: String,
    pub password: String,
}

#[derive(Debug, Serialize)]
pub struct LoginResponse {
    pub token: String,
    pub user: UserPublic,
}

#[derive(Debug, Serialize)]
pub struct HealthResponse {
    pub status: &'static str,
    pub version: &'static str,
}

// ---------------------------------------------------------------------------
// Route configuration
// ---------------------------------------------------------------------------

pub fn configure(cfg: &mut web::ServiceConfig) {
    cfg.service(
        web::scope("/auth")
            .route("/login", web::post().to(login))
            .route("/me", web::get().to(me))
            .route("/logout", web::post().to(logout)),
    )
    // Top-level health check (no /auth prefix)
    .route("/health", web::get().to(health));
}

// ---------------------------------------------------------------------------
// Handlers
// ---------------------------------------------------------------------------

/// POST /api/v1/auth/login
async fn login(
    pool: web::Data<DbPool>,
    req: HttpRequest,
    body: web::Json<LoginRequest>,
) -> Result<HttpResponse, AppError> {
    // 1. Basic validation
    if body.username.trim().is_empty() || body.password.trim().is_empty() {
        return Err(AppError::ValidationError(
            "username and password must not be empty".into(),
        ));
    }

    // 2. Fetch user by username
    let user_opt = sqlx::query_as::<_, User>(
        "SELECT id, username, email, password_hash, display_name, account_state, \
         created_at, updated_at \
         FROM users WHERE username = $1",
    )
    .bind(&body.username)
    .fetch_optional(pool.get_ref())
    .await?;

    let user = user_opt.ok_or_else(|| AppError::Unauthorized("Invalid credentials".into()))?;

    // 3. Verify password
    crate::services::auth::verify_password(&body.password, &user.password_hash)?;

    // 4. Check account state
    if user.account_state != "active" {
        // Still log the failed attempt before returning
        let ip = extract_ip(&req);
        let _ = log_access(
            pool.get_ref(),
            Some(user.id),
            "login",
            ip.as_deref(),
            false,
            Some(&format!("Account is {}", user.account_state)),
        )
        .await;

        return Err(AppError::Forbidden(format!(
            "Account is {}",
            user.account_state
        )));
    }

    // 5. Generate session token (64 hex chars = 32 random bytes)
    let token = generate_token();
    let session_id = Uuid::new_v4();
    let expires_at = Utc::now() + Duration::hours(1);
    let ip = extract_ip(&req);
    let user_agent = extract_user_agent(&req);

    sqlx::query(
        "INSERT INTO sessions (id, user_id, token, created_at, expires_at, ip_address, user_agent) \
         VALUES ($1, $2, $3, NOW(), $4, $5, $6)",
    )
    .bind(session_id)
    .bind(user.id)
    .bind(&token)
    .bind(expires_at)
    .bind(ip.as_deref())
    .bind(user_agent.as_deref())
    .execute(pool.get_ref())
    .await?;

    // 6. Log successful access
    let _ = log_access(
        pool.get_ref(),
        Some(user.id),
        "login",
        ip.as_deref(),
        true,
        None,
    )
    .await;

    // 7. Fetch roles for response
    let roles = fetch_user_roles(pool.get_ref(), user.id).await?;

    let user_public = UserPublic {
        id: user.id,
        username: user.username.clone(),
        email: user.email.clone(),
        display_name: user.display_name.clone(),
        account_state: user.account_state.clone(),
        roles,
        created_at: user.created_at,
    };

    Ok(HttpResponse::Ok().json(LoginResponse {
        token,
        user: user_public,
    }))
}

/// GET /api/v1/auth/me
async fn me(
    pool: web::Data<DbPool>,
    req: HttpRequest,
) -> Result<HttpResponse, AppError> {
    let token = extract_bearer_token_from_http(&req)?;
    let auth_user = resolve_authenticated_user(pool.get_ref(), &token).await?;

    // Fetch full user record for the response
    let user = sqlx::query_as::<_, User>(
        "SELECT id, username, email, password_hash, display_name, account_state, \
         created_at, updated_at \
         FROM users WHERE id = $1",
    )
    .bind(auth_user.user_id)
    .fetch_optional(pool.get_ref())
    .await?
    .ok_or_else(|| AppError::NotFound("User not found".into()))?;

    let user_public = UserPublic {
        id: user.id,
        username: user.username,
        email: user.email,
        display_name: user.display_name,
        account_state: user.account_state,
        roles: auth_user.roles,
        created_at: user.created_at,
    };

    Ok(HttpResponse::Ok().json(user_public))
}

/// POST /api/v1/auth/logout
async fn logout(
    pool: web::Data<DbPool>,
    req: HttpRequest,
) -> Result<HttpResponse, AppError> {
    let token = extract_bearer_token_from_http(&req)?;

    sqlx::query("DELETE FROM sessions WHERE token = $1")
        .bind(&token)
        .execute(pool.get_ref())
        .await?;

    Ok(HttpResponse::Ok().json(serde_json::json!({ "message": "Logged out successfully" })))
}

/// GET /api/v1/health
async fn health() -> HttpResponse {
    HttpResponse::Ok().json(HealthResponse {
        status: "ok",
        version: "0.1.0",
    })
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

fn generate_token() -> String {
    let bytes: [u8; 32] = rand::thread_rng().gen();
    bytes.iter().map(|b| format!("{:02x}", b)).collect()
}

fn extract_ip(req: &HttpRequest) -> Option<String> {
    // Check X-Forwarded-For first, fall back to peer address
    req.headers()
        .get("X-Forwarded-For")
        .and_then(|v| v.to_str().ok())
        .map(|s| s.split(',').next().unwrap_or(s).trim().to_string())
        .or_else(|| {
            req.peer_addr()
                .map(|addr| addr.ip().to_string())
        })
}

fn extract_user_agent(req: &HttpRequest) -> Option<String> {
    req.headers()
        .get("User-Agent")
        .and_then(|v| v.to_str().ok())
        .map(|s| s.to_string())
}

/// Extract Bearer token from an HttpRequest (as opposed to ServiceRequest).
fn extract_bearer_token_from_http(req: &HttpRequest) -> Result<String, AppError> {
    req.headers()
        .get("Authorization")
        .and_then(|v| v.to_str().ok())
        .and_then(|v| v.strip_prefix("Bearer "))
        .map(|s| s.to_string())
        .ok_or_else(|| AppError::Unauthorized("Missing or invalid Authorization header".into()))
}

async fn fetch_user_roles(pool: &DbPool, user_id: Uuid) -> Result<Vec<String>, AppError> {
    let roles = sqlx::query_scalar::<_, String>(
        "SELECT r.name FROM roles r \
         JOIN user_roles ur ON r.id = ur.role_id \
         WHERE ur.user_id = $1",
    )
    .bind(user_id)
    .fetch_all(pool)
    .await?;
    Ok(roles)
}

async fn log_access(
    pool: &DbPool,
    user_id: Option<Uuid>,
    action: &str,
    ip_address: Option<&str>,
    success: bool,
    details: Option<&str>,
) -> Result<(), AppError> {
    sqlx::query(
        "INSERT INTO access_logs (id, user_id, action, ip_address, success, details, created_at) \
         VALUES ($1, $2, $3, $4, $5, $6, NOW())",
    )
    .bind(Uuid::new_v4())
    .bind(user_id)
    .bind(action)
    .bind(ip_address)
    .bind(success)
    .bind(details)
    .execute(pool)
    .await?;
    Ok(())
}

use yew::prelude::*;
use yew_router::prelude::*;
use crate::router::Route;
use crate::state::{AppState, AppStateContext};
use crate::components::layout::Layout;
use crate::pages::login::LoginPage;
use crate::pages::unauthorized::UnauthorizedPage;
use crate::pages::home::HomePage;
use crate::api::auth;

fn switch(route: Route) -> Html {
    match route {
        Route::Login => html! { <LoginPage /> },
        Route::Unauthorized => html! { <UnauthorizedPage /> },
        Route::Home | Route::NotFound => html! { <AuthGuard /> },
    }
}

#[function_component(AuthGuard)]
fn auth_guard() -> Html {
    let state = use_context::<AppStateContext>().expect("AppState context not found");
    let navigator = use_navigator().unwrap();
    let authenticated = state.is_authenticated();

    // Hooks must be called unconditionally — redirect happens inside the effect
    {
        let navigator = navigator.clone();
        use_effect_with(authenticated, move |&auth| {
            if !auth {
                navigator.push(&Route::Login);
            }
        });
    }

    if authenticated {
        html! { <HomePage /> }
    } else {
        html! { <div class="loading">{ "Redirecting\u{2026}" }</div> }
    }
}

#[function_component(App)]
pub fn app() -> Html {
    let app_state = use_state(AppState::default);

    // On mount, if we have a stored token, validate it by fetching the current user.
    {
        let app_state = app_state.clone();
        use_effect_with((), move |_| {
            let app_state = app_state.clone();
            if let Some(token) = (*app_state).token.clone() {
                wasm_bindgen_futures::spawn_local(async move {
                    match auth::me(&token).await {
                        Ok(user) => {
                            let mut new_state = (*app_state).clone();
                            new_state.user = Some(user);
                            app_state.set(new_state);
                        }
                        Err(_) => {
                            // Token is invalid or expired — clear it.
                            let mut new_state = (*app_state).clone();
                            new_state.logout();
                            app_state.set(new_state);
                        }
                    }
                });
            }
        });
    }

    let on_logout = {
        let app_state = app_state.clone();
        Callback::from(move |_: ()| {
            let token = (*app_state).token.clone();
            let app_state = app_state.clone();
            wasm_bindgen_futures::spawn_local(async move {
                if let Some(t) = token {
                    let _ = auth::logout(&t).await;
                }
                let mut new_state = (*app_state).clone();
                new_state.logout();
                app_state.set(new_state);
            });
        })
    };

    html! {
        <ContextProvider<AppStateContext> context={app_state.clone()}>
            <BrowserRouter>
                <div id="app">
                    <Layout on_logout={on_logout}>
                        <Switch<Route> render={switch} />
                    </Layout>
                </div>
            </BrowserRouter>
        </ContextProvider<AppStateContext>>
    }
}
