```rust
use actix_web::{FromRequest, HttpRequest, web};
use std::future::Future;
use std::pin::Pin;

/// Request-scoped authenticated user. Use as a handler parameter to require authentication.
/// Returns 401 if no/invalid token, 403 if account blocked.
pub struct AuthContext(pub AuthenticatedUser);

impl AuthContext {
    pub fn user(&self) -> &AuthenticatedUser { &self.0 }

    /// Returns Forbidden if the user does not have the specified role.
    pub fn require_role(&self, role: &str) -> Result<(), crate::errors::AppError> {
        if self.0.roles.iter().any(|r| r == role) {
            Ok(())
        } else {
            Err(crate::errors::AppError::Forbidden(
                format!("This action requires the {} role.", role)
            ))
        }
    }

    /// Returns Forbidden if the user has none of the specified roles.
    pub fn require_any_role(&self, roles: &[&str]) -> Result<(), crate::errors::AppError> {
        if roles.iter().any(|r| self.0.roles.iter().any(|ur| ur == r)) {
            Ok(())
        } else {
            Err(crate::errors::AppError::Forbidden(
                "You do not have permission to perform this action.".into()
            ))
        }
    }

    pub fn is_admin(&self) -> bool { self.0.roles.iter().any(|r| r == "Administrator") }
    pub fn is_teacher(&self) -> bool { self.0.roles.iter().any(|r| r == "Teacher") }
}

impl FromRequest for AuthContext {
    type Error = crate::errors::AppError;
    type Future = Pin<Box<dyn Future<Output = Result<Self, Self::Error>>>>;

    fn from_request(req: &HttpRequest, _payload: &mut actix_web::dev::Payload) -> Self::Future {
        let token = req
            .headers()
            .get("Authorization")
            .and_then(|v| v.to_str().ok())
            .and_then(|v| v.strip_prefix("Bearer "))
            .map(|s| s.to_string());

        let pool = req.app_data::<web::Data<crate::db::DbPool>>().cloned();

        Box::pin(async move {
            let token = token.ok_or_else(|| {
                crate::errors::AppError::Unauthorized("Missing Authorization header".into())
            })?;
            let pool = pool.ok_or_else(|| {
                crate::errors::AppError::InternalError("DB pool not configured".into())
            })?;
            let user = resolve_authenticated_user(pool.get_ref(), &token).await?;
            Ok(AuthContext(user))
        })
    }
}
```

