                            oninput={on_password_input}
                            autocomplete="current-password"
                            disabled={*loading || is_form_blocked}
                        />
                    </div>
                    { error_banner }
                    <button class="btn-primary" type="submit"
                        disabled={*loading || is_form_blocked}>
                        { button_text }
                    </button>
                </form>
            </div>
        </div>
    }
}
